import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import AuthForm from './components/AuthForm';
import Dashboard from './pages/Dashboard';
import Recommendations from './pages/Recommendations';
import api from './api/api'; // Import api to use for initial fetch

const App = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [profile, setProfile] = useState({});
  const [appLoading, setAppLoading] = useState(true); // NEW: Global loading state

  const handleAuth = (token, profileData) => {
    localStorage.setItem('token', token);
    setIsLoggedIn(true);
    setProfile(profileData || {});
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    setIsLoggedIn(false);
    setProfile({});
  };
  
  // NEW: Function to fetch profile data and set the state
  const fetchProfileData = async () => {
    if (!localStorage.getItem('token')) {
        setAppLoading(false);
        return;
    }
    try {
        const response = await api.get('/profile');
        setProfile(response.data.profile);
    } catch (err) {
        console.error("Initial profile fetch failed, logging out:", err);
        // If token fails validation on first fetch, clear it and log out
        handleLogout(); 
    } finally {
        setAppLoading(false);
    }
  };

  useEffect(() => {
    if (localStorage.getItem('token')) {
      setIsLoggedIn(true);
      fetchProfileData(); // Trigger initial data fetch if logged in
    } else {
      setAppLoading(false);
    }
  }, [isLoggedIn]); // Re-run when login status changes

  // Protected Route Wrapper
  const ProtectedRoute = ({ children }) => {
    if (!isLoggedIn) {
      return <Navigate to="/" replace />;
    }
    // Dashboard component now expects to receive fully loaded data or loading state managed by App.jsx
    return children;
  };
  
  if (appLoading) {
      // Show loading screen while waiting for the initial profile fetch to complete
      return <div className="min-h-screen bg-gray-100 p-8 text-center text-2xl font-bold pt-40">Loading Application Data...</div>;
  }

  return (
    <Router>
      <div className="min-h-screen bg-gray-100 p-8">
        <h1 className="text-3xl font-bold text-center mb-6 text-blue-800">
          AI-Powered Personalized Fitness System
        </h1>
        {isLoggedIn && (
          <button onClick={handleLogout} className="absolute top-4 right-4 bg-red-500 text-white px-4 py-2 rounded shadow-md hover:bg-red-600 transition">
            Logout
          </button>
        )}
        <Routes>
          <Route path="/" element={isLoggedIn ? <Navigate to="/dashboard" /> : <AuthForm onAuthSuccess={handleAuth} />} />
          
          <Route path="/dashboard" element={
            <ProtectedRoute>
              {/* Pass fetchProfileData down as the refresh function */}
              <Dashboard profile={profile} setProfile={setProfile} fetchProfile={fetchProfileData} /> 
            </ProtectedRoute>
          } />

          <Route path="/recommendations" element={
            <ProtectedRoute>
              <Recommendations profile={profile} />
            </ProtectedRoute>
          } />
          
          <Route path="*" element={<Navigate to="/dashboard" />} />
        </Routes>
      </div>
    </Router>
  );
};

export default App;
